INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES ("リン", 0.0, 10040, 24, 0, 0.0, 1, 102601, "2030/12/17 14:59:59", 1, "あたしだって\nやるときはやるよ！", 24001, 0.0, "2020/04/30 12:00:00");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES ("リン", 0.0, 10040, 24, 1, 0.0, 1, 102601, "2030/12/17 14:59:59", 1, "ふぅ…\nこれであたしの仕事は\n終わりだね", 24002, 0.0, "2020/04/30 12:00:00");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES ("リン", 0.0, 10040, 24, 2, 0.0, 1, 102601, "2030/12/17 14:59:59", 1, "終わった終わった\n一人でもなんとか\nなるもんだね", 24003, 0.0, "2020/04/30 12:00:00");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES ("リン", 0.0, 10040, 24, 3, 0.0, 2, 102601, "2030/12/17 14:59:59", 2, "やったね！\nこれでようやく\nサボれるよ…", 24004, 0.0, "2020/04/30 12:00:00");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES ("リン", 0.0, 10040, 24, 4, 0.0, 1, 102601, "2030/12/17 14:59:59", 1, "チーズが欲しいなら\nきちんと働いて\n買いに来なよ", 24005, 0.0, "2020/04/30 12:00:00");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES ("リン", 0.0, 10040, 24, 5, 0.0, 2, 102601, "2030/12/17 14:59:59", 2, "あたしを敵に回した\n恐ろしさ\n思い知ったか！", 24006, 0.0, "2020/04/30 12:00:00");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES ("リン", 0.0, 10040, 24, 6, 0.0, 2, 102601, "2030/12/17 14:59:59", 2, "あたしも意外と\nやるもんでしょ？", 24007, 0.0, "2020/04/30 12:00:00");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES ("リン", 0.0, 10040, 24, 7, 0.0, 4, 102601, "2030/12/17 14:59:59", 4, "疲れた…\nねずみの逃げ足\n速すぎるよ…", 24008, 0.0, "2020/04/30 12:00:00");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES ("リン", 0.0, 10040, 24, 8, 0.0, 4, 102601, "2030/12/17 14:59:59", 4, "このままじゃ\nまっひ～に\n叱られちゃうよ", 24009, 0.0, "2020/04/30 12:00:00");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES ("リン", 0.0, 10040, 24, 9, 0.0, 4, 102601, "2030/12/17 14:59:59", 4, "まじめに\nやったんだけどな…\n悔しいな～", 24010, 0.0, "2020/04/30 12:00:00");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES ("リン", 0.0, 10040, 24, 10, 0.0, 4, 102601, "2030/12/17 14:59:59", 4, "やられた…\nねずみって意外と\nてごわいね", 24011, 0.0, "2020/04/30 12:00:00");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES ("リン", 0.0, 10040, 24, 11, 0.0, 4, 102601, "2030/12/17 14:59:59", 4, "おのれ～\nあたしのチーズを\n盗みやがって～！", 24012, 0.0, "2020/04/30 12:00:00");
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES ("リン", 0.0, 10040, 24, 12, 0.0, 1, 102601, "2030/12/17 14:59:59", 4, "疲れた…\nけど、次こそは\n守り抜くよ…", 24013, 1.81, "2020/04/30 12:00:00");
